def pow(base: Long, exponent: Long, mod: Long): Long = {
  var result = 1L
  var power = base % mod
  var exponentCopy = exponent
  while (exponentCopy > 0) {
    if (exponentCopy % 2 == 1) {
      result = (result * power) % mod
    }
    power = (power * power) % mod
    exponentCopy /= 2
  }
  result
}
